package com.volcengine.auth;

/**
 * Manual test for OidcCredentialProvider auto-generated session name.
 */
public class OidcCredentialProviderTest {

    public static void main(String[] args) {
        testAutoGeneratedSessionName();
        System.out.println("All OidcCredentialProvider tests passed.");
    }

    static void testAutoGeneratedSessionName() {
        // When roleSessionName is null, should auto-generate with "credentials-java-" prefix
        try {
            OidcCredentialProvider provider = new OidcCredentialProvider(
                    "trn:iam::123:role/test",
                    null,  // roleSessionName = null, should auto-generate
                    "/tmp/nonexistent_token_file",
                    null, null);
            assert provider != null : "Provider should be created successfully";
            System.out.println("PASS: testAutoGeneratedSessionName");
        } catch (IllegalArgumentException e) {
            throw new AssertionError("Should not throw when roleSessionName is null: " + e.getMessage());
        }
    }
}
